import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import {
  logout as serviceLogout,
  logoutFromServer,
  getStoredSession,
  fetchCurrentUser,
} from '../services/authService';
import { setUnauthorizedHandler } from '../adapters/unauthorizedHandler';
import { getInitials } from '../utils/getInitials';
import { hasPermission } from '../constants/roles';
import { API_BASE_URL } from '../constants/config';
import { fetchBillingProfilesFromApi } from '../constants/billingProfiles';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [session, setSession] = useState(() => getStoredSession());
  // Loading is true only when we have a stored token to validate against the backend
  const [loading, setLoading] = useState(() => {
    if (!API_BASE_URL) return false;
    return Boolean(localStorage.getItem('auth_token'));
  });

  /**
   * On app load, validate the stored token against the backend.
   * This catches tokens that were revoked server-side.
   */
  useEffect(() => {
    const storedToken = localStorage.getItem('auth_token');
    if (!API_BASE_URL || !storedToken) {
      return;
    }

    fetchCurrentUser(storedToken)
      .then((user) => {
        if (user) {
          localStorage.setItem('auth_user', JSON.stringify(user));
          setSession({ token: storedToken, user });
          fetchBillingProfilesFromApi().catch(() => {});
        } else {
          // Token is invalid — clear session
          serviceLogout();
          setSession(null);
        }
      })
      .catch(() => {
        setSession(null);
      })
      .finally(() => setLoading(false));
    // On mount only — runs once to validate the stored token on startup
  }, []);

  /** Called after any successful login to push session into context. */
  const login = useCallback((token, user) => {
    setSession({ token, user });
    fetchBillingProfilesFromApi().catch(() => {});
  }, []);

  /** Clear session from context AND from localStorage; notify the server. */
  const logout = useCallback(() => {
    const token = session?.token;
    logoutFromServer(token);
    serviceLogout();
    setSession(null);
  }, [session]);

  useEffect(() => {
    setUnauthorizedHandler(() => logout());
    return () => setUnauthorizedHandler(null);
  }, [logout]);

  const isAuthenticated = Boolean(session?.token);

  /**
   * Check whether the current user has the given permission.
   * Always returns true for the wildcard '*' (super_admin).
   *
   * @param {string} permission  e.g. 'clients.view'
   * @returns {boolean}
   */
  const checkPermission = useCallback((permission) => {
    return hasPermission(session?.user?.permissions, permission);
  }, [session]);

  const checkAnyPermission = useCallback((permissions) => {
    if (!permissions || permissions.length === 0) return false;
    return permissions.some((p) => hasPermission(session?.user?.permissions, p));
  }, [session]);

  /** Merge fields into the stored user (e.g. after profile save). */
  const updateSessionUser = useCallback((user) => {
    setSession((prev) => {
      if (!prev) return prev;
      const merged = {
        ...prev.user,
        ...user,
        initials: user?.initials ?? getInitials(user?.name || prev.user?.name || ''),
      };
      localStorage.setItem('auth_user', JSON.stringify(merged));
      return { ...prev, user: merged };
    });
  }, []);

  return (
    <AuthContext.Provider value={{
      session,
      user: session?.user ?? null,
      isAuthenticated,
      loading,
      login,
      logout,
      updateSessionUser,
      hasPermission: checkPermission,
      hasAnyPermission: checkAnyPermission,
    }}>
      {children}
    </AuthContext.Provider>
  );
}

/** Hook for accessing the auth context in any component. */
// eslint-disable-next-line react-refresh/only-export-components
export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside <AuthProvider>');
  return ctx;
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useSyncProp } from '../../hooks/useSyncProp';
import { getOrganizationsForSearch } from '../../modules/crm/services/organizationService';

const MIN_QUERY_LENGTH = 2;
const SEARCH_LIMIT = 50;
const DEBOUNCE_MS = 300;

/**
 * OrganizationSearchDropdown
 *
 * Debounced autocomplete for searching organizations by name, PAN, GSTIN, etc.
 * Excludes inactive organizations (active + prospect only).
 *
 * Props:
 *   value         {number|string}  Currently selected organization ID.
 *   displayValue  {string}         Currently selected organization display name.
 *   onChange      {function}       Called with ({ id, displayName }) when selected.
 *   placeholder   {string}         Input placeholder text.
 *   style         {object}         Extra styles for the input element.
 */
export default function OrganizationSearchDropdown({
  value,
  displayValue = '',
  onChange,
  placeholder = 'Search organization by name…',
  style = {},
}) {
  const [query, setQuery] = useSyncProp(displayValue || '', (v) => v || '');
  const [suggestions, setSuggestions] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const debounceRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    setQuery(displayValue || '');
  }, [displayValue]);

  useEffect(() => {
    function handleClick(e) {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const doSearch = useCallback(async (q) => {
    const trimmed = q.trim();
    if (!trimmed || trimmed.length < MIN_QUERY_LENGTH) {
      setSuggestions([]);
      setOpen(trimmed.length > 0);
      return;
    }
    setLoading(true);
    try {
      const rows = await getOrganizationsForSearch(trimmed, SEARCH_LIMIT);
      const filtered = rows.filter(o => o.status !== 'inactive');
      setSuggestions(filtered.map(o => ({
        id: o.id,
        displayName: o.displayName,
      })));
      setOpen(true);
    } catch {
      setSuggestions([]);
      setOpen(true);
    } finally {
      setLoading(false);
    }
  }, []);

  function handleInput(e) {
    const val = e.target.value;
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(val), DEBOUNCE_MS);
    if (!val.trim()) {
      setSuggestions([]);
      setOpen(false);
    }
  }

  function handleFocus() {
    const t = query.trim();
    if (t.length >= MIN_QUERY_LENGTH) {
      doSearch(query);
    } else {
      setOpen(true);
    }
  }

  function handleSelect(org) {
    setQuery(org.displayName);
    setSuggestions([]);
    setOpen(false);
    if (onChange) onChange(org);
  }

  const inputStyle = {
    padding: '8px 10px',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    fontSize: 13,
    color: '#334155',
    outline: 'none',
    width: '100%',
    boxSizing: 'border-box',
    ...style,
  };

  const dropdownStyle = {
    position: 'absolute',
    top: '100%',
    left: 0,
    right: 0,
    zIndex: 9999,
    background: '#fff',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
    maxHeight: 240,
    overflowY: 'auto',
    marginTop: 2,
  };

  const itemStyle = {
    padding: '8px 12px',
    cursor: 'pointer',
    fontSize: 13,
    color: '#334155',
    background: '#fff',
    borderBottom: '1px solid #f8fafc',
  };

  const trimmedQuery = query.trim();
  const showHint = open && !loading && trimmedQuery.length < MIN_QUERY_LENGTH;
  const showEmpty = open && !loading && trimmedQuery.length >= MIN_QUERY_LENGTH && suggestions.length === 0;

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <input
        type="text"
        value={query}
        onChange={handleInput}
        onFocus={handleFocus}
        placeholder={placeholder}
        style={inputStyle}
        autoComplete="off"
      />
      {loading && (
        <span style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', fontSize: 11, color: '#94a3b8' }}>…</span>
      )}
      {open && (
        <div style={dropdownStyle}>
          {showHint && (
            <div style={{ padding: '8px 12px', fontSize: 12, color: '#94a3b8' }}>
              Type at least {MIN_QUERY_LENGTH} characters to search organizations…
            </div>
          )}
          {showEmpty && (
            <div style={{ padding: '8px 12px', fontSize: 12, color: '#94a3b8' }}>No organizations found</div>
          )}
          {suggestions.map(o => (
            <div
              key={o.id}
              style={{
                ...itemStyle,
                background: String(o.id) === String(value) ? '#f0f4ff' : '#fff',
              }}
              onMouseEnter={e => { if (String(o.id) !== String(value)) e.currentTarget.style.background = '#f0f4ff'; }}
              onMouseLeave={e => { if (String(o.id) !== String(value)) e.currentTarget.style.background = '#fff'; }}
              onMouseDown={() => handleSelect(o)}
            >
              {o.displayName}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { createContext, useContext, useState, useCallback, useEffect, useLayoutEffect } from 'react';
import { useAuth } from '../auth/AuthContext';
import { updateCurrentUserProfile } from '../services/authService';
import { API_BASE_URL } from '../constants/config';
import {
  DEFAULT_THEME_ID,
  applyPortalTheme,
  resolveThemeId,
  resolveUserTheme,
  setStoredThemeForUser,
} from '../theme/portalThemes';

const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
  const { session, user, updateSessionUser } = useAuth();
  const token = session?.token;

  const [themeId, setThemeId] = useState(() => {
    if (user) return resolveUserTheme(user);
    return DEFAULT_THEME_ID;
  });
  const [draftThemeId, setDraftThemeId] = useState(themeId);
  const [saving, setSaving] = useState(false);

  useLayoutEffect(() => {
    const resolved = user ? resolveUserTheme(user) : DEFAULT_THEME_ID;
    setThemeId(resolved);
    setDraftThemeId(resolved);
    applyPortalTheme(resolved);
  }, [user]);

  useEffect(() => {
    if (!user) {
      applyPortalTheme(DEFAULT_THEME_ID);
    }
  }, [user]);

  const selectTheme = useCallback((id) => {
    const resolved = resolveThemeId(id);
    setDraftThemeId(resolved);
    applyPortalTheme(resolved);
  }, []);

  const resetDraft = useCallback(() => {
    setDraftThemeId(themeId);
    applyPortalTheme(themeId);
  }, [themeId]);

  const saveTheme = useCallback(async (id) => {
    const resolved = resolveThemeId(id ?? draftThemeId);
    if (!user) throw new Error('Sign in to save your theme preference.');

    setSaving(true);
    try {
      if (API_BASE_URL && token) {
        const updated = await updateCurrentUserProfile(token, { portal_theme: resolved });
        updateSessionUser(updated);
      } else {
        setStoredThemeForUser(user.id, resolved);
        updateSessionUser({ portal_theme: resolved });
      }
      setThemeId(resolved);
      setDraftThemeId(resolved);
      applyPortalTheme(resolved);
      return resolved;
    } finally {
      setSaving(false);
    }
  }, [draftThemeId, token, updateSessionUser, user]);

  const isDirty = draftThemeId !== themeId;

  return (
    <ThemeContext.Provider value={{
      themeId,
      draftThemeId,
      isDirty,
      saving,
      selectTheme,
      resetDraft,
      saveTheme,
    }}>
      {children}
    </ThemeContext.Provider>
  );
}

// eslint-disable-next-line react-refresh/only-export-components
export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used inside <ThemeProvider>');
  return ctx;
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useSyncProp } from '../../../hooks/useSyncProp';
import { API_BASE_URL } from '../../../constants/config';
import { formatEntityLabel, EntityNameWithReference } from '../../../utils/entityDisplay';

const API_BASE = API_BASE_URL;

function authHeaders() {
  const token = localStorage.getItem('auth_token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
}

/**
 * ClientSearchDropdown
 *
 * A debounced autocomplete input that lets users search for clients by name,
 * email, or PAN.  Designed to handle ~1,000 client records efficiently.
 *
 * Props:
 *   value         {number|string}  Currently selected client ID (controlled).
 *   displayValue  {string}         Currently selected client display name.
 *   onChange      {function}       Called with ({ id, displayName }) when a client is selected.
 *   placeholder   {string}         Input placeholder text.
 *   style         {object}         Extra styles for the input element.
 *   allowAll      {boolean}        If true, shows an "All Clients" option when no query.
 *   onAllClients  {function}       Called when "All Clients" is selected (requires allowAll).
 *   minQueryLength {number}       Minimum trimmed characters before searching (default 1).
 *   searchLimit   {number}        Max results from /contacts/search (default 20, max 50).
 *   clearSelectionWhenInputEmpty {boolean} If true, clearing the input calls onChange({ id:'', displayName:'' }).
 */
export default function ClientSearchDropdown({
  displayValue = '',
  onChange,
  placeholder = 'Search client…',
  style = {},
  allowAll = false,
  onAllClients,
  minQueryLength = 1,
  searchLimit = 20,
  clearSelectionWhenInputEmpty = false,
}) {
  const [query, setQuery] = useSyncProp(displayValue || '', (v) => v || '');
  const [suggestions, setSuggestions] = useState([]);
  const [open, setOpen]             = useState(false);
  const [loading, setLoading]       = useState(false);
  const debounceRef                 = useRef(null);
  const containerRef                = useRef(null);

  // Keep the input text in sync when the parent changes the displayValue
  useEffect(() => {
    setQuery(displayValue || '');
  }, [displayValue]);

  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClick(e) {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const doSearch = useCallback(async (q) => {
    const trimmed = q.trim();
    if (!trimmed || trimmed.length < minQueryLength) {
      setSuggestions([]);
      setOpen(false);
      return;
    }
    const limit = Math.min(50, Math.max(1, searchLimit));
    setLoading(true);
    try {
      const params = new URLSearchParams({ q: trimmed, limit: String(limit) });
      const res = await fetch(`${API_BASE}/admin/contacts/search?${params}`, {
        headers: authHeaders(),
      });
      const data = await res.json().catch(() => ({}));
      if (res.ok) {
        const rows = (data.data || []).map(c => {
          const parts = [c.first_name, c.last_name].filter(Boolean);
          return {
            id:          c.id,
            displayName: c.organization_name || parts.join(' ') || 'Unknown',
            reference:   c.reference || '',
          };
        });
        setSuggestions(rows);
        setOpen(true);
      }
    } catch {
      // ignore search errors
    } finally {
      setLoading(false);
    }
  }, [minQueryLength, searchLimit]);

  function handleInput(e) {
    const val = e.target.value;
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(val), 300);
    if (!val.trim()) {
      setSuggestions([]);
      setOpen(false);
      if (clearSelectionWhenInputEmpty && onChange) {
        onChange({ id: '', displayName: '' });
      }
    }
  }

  function handleFocus() {
    const t = query.trim();
    if (t.length >= minQueryLength) {
      doSearch(query);
    } else if (allowAll) {
      setOpen(true);
    }
  }

  function handleSelect(client) {
    const label = formatEntityLabel(client.displayName, client.reference);
    setQuery(label);
    setSuggestions([]);
    setOpen(false);
    if (onChange) onChange({ ...client, displayName: label });
  }

  function handleAllClients() {
    setQuery('');
    setSuggestions([]);
    setOpen(false);
    if (onAllClients) onAllClients();
  }

  const inputStyle = {
    padding: '8px 10px',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    fontSize: 13,
    color: '#334155',
    outline: 'none',
    width: '100%',
    boxSizing: 'border-box',
    ...style,
  };

  const dropdownStyle = {
    position: 'absolute',
    top: '100%',
    left: 0,
    right: 0,
    zIndex: 9999,
    background: '#fff',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
    maxHeight: 240,
    overflowY: 'auto',
    marginTop: 2,
  };

  const itemStyle = (hovered) => ({
    padding: '8px 12px',
    cursor: 'pointer',
    fontSize: 13,
    color: '#334155',
    background: hovered ? '#f0f4ff' : '#fff',
    borderBottom: '1px solid #f8fafc',
  });

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <input
        type="text"
        value={query}
        onChange={handleInput}
        onFocus={handleFocus}
        placeholder={placeholder}
        style={inputStyle}
        autoComplete="off"
      />
      {loading && (
        <span style={{ position:'absolute', right:10, top:'50%', transform:'translateY(-50%)', fontSize:11, color:'#94a3b8' }}>…</span>
      )}
      {open && (
        <div style={dropdownStyle}>
          {allowAll && (
            <div
              style={{ ...itemStyle(false), fontStyle:'italic', color:'#64748b' }}
              onMouseDown={handleAllClients}
            >
              All Clients
            </div>
          )}
          {suggestions.length === 0 && !loading && query.trim().length >= minQueryLength && (
            <div style={{ padding:'8px 12px', fontSize:12, color:'#94a3b8' }}>No clients found</div>
          )}
          {suggestions.map(c => (
            <div
              key={c.id}
              style={itemStyle(false)}
              onMouseEnter={e => { e.currentTarget.style.background = '#f0f4ff'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#fff'; }}
              onMouseDown={() => handleSelect(c)}
            >
              <EntityNameWithReference displayName={c.displayName} reference={c.reference} />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useSyncProp } from '../../../hooks/useSyncProp';
import { API_BASE_URL } from '../../../constants/config';
import { formatEntityLabel, EntityNameWithReference } from '../../../utils/entityDisplay';

const API_BASE = API_BASE_URL;

function authHeaders() {
  const token = localStorage.getItem('auth_token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
}

/**
 * EntitySearchDropdown
 *
 * A debounced autocomplete input that lets users search for either a Contact
 * or an Organization. A Contact | Organization toggle tab at the top of the
 * dropdown switches the active search source.
 *
 * Props:
 *   value         {number|string}          Currently selected entity ID.
 *   displayValue  {string}                 Currently selected entity display name.
 *   entityType    {'contact'|'organization'} Controlled entity type (default: 'contact').
 *   onChange      {function}               Called with ({ id, displayName, entityType }).
 *   placeholder   {string}                 Input placeholder text.
 *   style         {object}                 Extra styles for the input element.
 *   allowAll      {boolean}                If true, shows an "All" option when no query.
 *   onAllClients  {function}               Called when "All" is selected (requires allowAll).
 */
export default function EntitySearchDropdown({
  displayValue = '',
  entityType: controlledEntityType,
  onChange,
  placeholder = 'Search…',
  style = {},
  allowAll = false,
  onAllClients,
}) {
  const [activeType, setActiveType] = useSyncProp(controlledEntityType || 'contact', (v) => v || 'contact');
  const [query, setQuery] = useSyncProp(displayValue || '', (v) => v || '');
  const [suggestions, setSuggestions]     = useState([]);
  const [open, setOpen]                   = useState(false);
  const [loading, setLoading]             = useState(false);
  const debounceRef                       = useRef(null);
  const containerRef                      = useRef(null);

  // Keep the input text in sync when the parent changes the displayValue
  useEffect(() => {
    setQuery(displayValue || '');
  }, [displayValue]);

  // Keep activeType in sync when parent controls entityType
  useEffect(() => {
    if (controlledEntityType) setActiveType(controlledEntityType);
  }, [controlledEntityType]);

  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClick(e) {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const doSearch = useCallback(async (q, type) => {
    if (!q.trim()) {
      setSuggestions([]);
      setOpen(false);
      return;
    }
    setLoading(true);
    try {
      let rows = [];
      if (type === 'organization') {
        const params = new URLSearchParams({ q: q.trim(), limit: 20 });
        const res = await fetch(`${API_BASE}/admin/organizations/search?${params}`, {
          headers: authHeaders(),
        });
        const data = await res.json().catch(() => ({}));
        if (res.ok) {
          rows = (data.data || []).map(o => ({
            id:          o.id,
            displayName: o.name || 'Unknown',
            reference:   o.reference || '',
            entityType:  'organization',
          }));
        }
      } else {
        const params = new URLSearchParams({ q: q.trim(), limit: 20 });
        const res = await fetch(`${API_BASE}/admin/contacts/search?${params}`, {
          headers: authHeaders(),
        });
        const data = await res.json().catch(() => ({}));
        if (res.ok) {
          rows = (data.data || []).map(c => {
            const parts = [c.first_name, c.last_name].filter(Boolean);
            return {
              id:          c.id,
              displayName: c.organization_name || parts.join(' ') || 'Unknown',
              reference:   c.reference || '',
              entityType:  'contact',
            };
          });
        }
      }
      setSuggestions(rows);
      setOpen(true);
    } catch {
      // ignore search errors
    } finally {
      setLoading(false);
    }
  }, []);

  function handleInput(e) {
    const val = e.target.value;
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(val, activeType), 300);
    if (!val.trim()) {
      setSuggestions([]);
      setOpen(false);
    }
  }

  function handleFocus() {
    if (query.trim()) {
      doSearch(query, activeType);
    } else if (allowAll) {
      setOpen(true);
    }
  }

  function handleSelect(entity) {
    const label = formatEntityLabel(entity.displayName, entity.reference);
    setQuery(label);
    setSuggestions([]);
    setOpen(false);
    if (onChange) onChange({ ...entity, displayName: label });
  }

  function handleAllClients() {
    setQuery('');
    setSuggestions([]);
    setOpen(false);
    if (onAllClients) onAllClients();
  }

  function handleTypeChange(type) {
    setActiveType(type);
    setSuggestions([]);
    if (query.trim()) {
      doSearch(query, type);
    }
  }

  const inputStyle = {
    padding: '8px 10px',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    fontSize: 13,
    color: '#334155',
    outline: 'none',
    width: '100%',
    boxSizing: 'border-box',
    ...style,
  };

  const dropdownStyle = {
    position: 'absolute',
    top: '100%',
    left: 0,
    right: 0,
    zIndex: 9999,
    background: '#fff',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
    maxHeight: 280,
    overflowY: 'auto',
    marginTop: 2,
  };

  const itemStyle = (hovered) => ({
    padding: '8px 12px',
    cursor: 'pointer',
    fontSize: 13,
    color: '#334155',
    background: hovered ? '#f0f4ff' : '#fff',
    borderBottom: '1px solid #f8fafc',
  });

  const tabBarStyle = {
    display: 'flex',
    borderBottom: '1px solid #f1f5f9',
    background: '#f8fafc',
  };

  const tabStyle = (active) => ({
    flex: 1,
    padding: '6px 0',
    fontSize: 11,
    fontWeight: 700,
    textAlign: 'center',
    cursor: 'pointer',
    color: active ? '#2563eb' : '#64748b',
    background: 'none',
    border: 'none',
    borderBottom: active ? '2px solid #2563eb' : '2px solid transparent',
    userSelect: 'none',
  });

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <input
        type="text"
        value={query}
        onChange={handleInput}
        onFocus={handleFocus}
        placeholder={placeholder}
        style={inputStyle}
        autoComplete="off"
      />
      {loading && (
        <span style={{ position:'absolute', right:10, top:'50%', transform:'translateY(-50%)', fontSize:11, color:'#94a3b8' }}>…</span>
      )}
      {open && (
        <div style={dropdownStyle}>
          {/* Contact | Organization toggle */}
          <div style={tabBarStyle}>
            <button
              style={tabStyle(activeType === 'contact')}
              onMouseDown={e => { e.preventDefault(); handleTypeChange('contact'); }}
            >
              Contact
            </button>
            <button
              style={tabStyle(activeType === 'organization')}
              onMouseDown={e => { e.preventDefault(); handleTypeChange('organization'); }}
            >
              Organization
            </button>
          </div>
          {allowAll && (
            <div
              style={{ ...itemStyle(false), fontStyle:'italic', color:'#64748b' }}
              onMouseDown={handleAllClients}
            >
              All
            </div>
          )}
          {suggestions.length === 0 && !loading && query.trim() && (
            <div style={{ padding:'8px 12px', fontSize:12, color:'#94a3b8' }}>
              No {activeType === 'organization' ? 'organizations' : 'contacts'} found
            </div>
          )}
          {suggestions.map(c => (
            <div
              key={c.id}
              style={itemStyle(false)}
              onMouseEnter={e => { e.currentTarget.style.background = '#f0f4ff'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#fff'; }}
              onMouseDown={() => handleSelect(c)}
            >
              <EntityNameWithReference displayName={c.displayName} reference={c.reference} />
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useSyncProp } from '../../../hooks/useSyncProp';
import { searchClientGroups } from '../services/clientGroupService';

/**
 * GroupSearchDropdown — debounced search against /admin/client-groups/search.
 *
 * Props:
 *   value, displayValue — controlled selection (id + label).
 *   onChange({ id, displayName }) — id '' when cleared.
 *   clearSelectionWhenInputEmpty — clearing the input removes the assignment.
 */
export default function GroupSearchDropdown({
  displayValue = '',
  onChange,
  placeholder = 'Search group by name…',
  style = {},
  minQueryLength = 1,
  searchLimit = 20,
  clearSelectionWhenInputEmpty = true,
}) {
  const [query, setQuery] = useSyncProp(displayValue || '', (v) => v || '');
  const [suggestions, setSuggestions] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const debounceRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    setQuery(displayValue || '');
  }, [displayValue]);

  useEffect(() => {
    function handleClick(e) {
      if (containerRef.current && !containerRef.current.contains(e.target)) {
        setOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  const doSearch = useCallback(async (q) => {
    const trimmed = q.trim();
    if (!trimmed || trimmed.length < minQueryLength) {
      setSuggestions([]);
      setOpen(false);
      return;
    }
    const lim = Math.min(50, Math.max(1, searchLimit));
    setLoading(true);
    try {
      const rows = await searchClientGroups(trimmed, lim);
      setSuggestions(
        (rows || []).map((g) => ({
          id: g.id,
          displayName: g.name || `Group #${g.id}`,
        }))
      );
      setOpen(true);
    } catch {
      setSuggestions([]);
      setOpen(false);
    } finally {
      setLoading(false);
    }
  }, [minQueryLength, searchLimit]);

  function handleInput(e) {
    const val = e.target.value;
    setQuery(val);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(val), 300);
    if (!val.trim()) {
      setSuggestions([]);
      setOpen(false);
      if (clearSelectionWhenInputEmpty && onChange) {
        onChange({ id: '', displayName: '' });
      }
    }
  }

  function handleFocus() {
    const t = query.trim();
    if (t.length >= minQueryLength) {
      doSearch(query);
    }
  }

  function handleSelect(row) {
    setQuery(row.displayName);
    setSuggestions([]);
    setOpen(false);
    if (onChange) onChange(row);
  }

  const inputStyle = {
    padding: '8px 10px',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    fontSize: 13,
    color: '#334155',
    outline: 'none',
    width: '100%',
    boxSizing: 'border-box',
    ...style,
  };

  const dropdownStyle = {
    position: 'absolute',
    top: '100%',
    left: 0,
    right: 0,
    zIndex: 9999,
    background: '#fff',
    border: '1px solid #e2e8f0',
    borderRadius: 6,
    boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
    maxHeight: 240,
    overflowY: 'auto',
    marginTop: 2,
  };

  const itemStyle = {
    padding: '8px 12px',
    cursor: 'pointer',
    fontSize: 13,
    color: '#334155',
    background: '#fff',
    borderBottom: '1px solid #f8fafc',
  };

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <input
        type="text"
        value={query}
        onChange={handleInput}
        onFocus={handleFocus}
        placeholder={placeholder}
        style={inputStyle}
        autoComplete="off"
      />
      {loading && (
        <span style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', fontSize: 11, color: '#94a3b8' }}>
          …
        </span>
      )}
      {open && (
        <div style={dropdownStyle}>
          {suggestions.length === 0 && !loading && query.trim().length >= minQueryLength && (
            <div style={{ padding: '8px 12px', fontSize: 12, color: '#94a3b8' }}>No groups found</div>
          )}
          {suggestions.map((g) => (
            <div
              key={g.id}
              style={itemStyle}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = '#f0f4ff';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = '#fff';
              }}
              onMouseDown={() => handleSelect(g)}
            >
              {g.displayName}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
